INSERT INTO app.concepts (id, course_id, code, name, status) VALUES ('00000000-0000-0000-0000-000000000101', '00000000-0000-0000-0000-000000000001', 'day1-basics', 'Phần 1: Khái niệm cơ bản LLM', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '7c4bf42c-b7f1-5214-8aa7-afc72ca02fc6',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Kiến trúc Transformer giới thiệu cơ chế nào giúp xử lý song song thay thế RNN?',   '{"options": {"A": "Cơ chế Convolutional Pooling.", "B": "Cơ chế Recurrent Gate.", "C": "Cơ chế Self Attention.", "D": "Cơ chế Feed Forward."}, "correct": "C", "explanation": "Cơ chế Self Attention cho phép các token trong chuỗi tương tác đồng thời với nhau, loại bỏ tính tuần tự của RNN/LSTM và tăng tốc độ tính toán song song."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'de4f8796-9d14-5542-a07e-d7e1877d979a',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Trong Scaled Dot-Product Attention, ba ma trận vectơ chính được sinh ra là gì?',   '{"options": {"A": "Query, Key và Value.", "B": "Input, Hidden và Output.", "C": "Encoder, Decoder và Latent.", "D": "Weights, Biases và Activations."}, "correct": "A", "explanation": "Query (truy vấn), Key (khóa) và Value (giá trị) là ba vectơ được tạo ra cho mỗi token nhằm tính toán mối liên hệ ngữ nghĩa trong attention."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '72690fa2-b584-5212-9f6f-ac6839322306',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Tại sao công thức Self-Attention lại chia cho hệ số tỷ lệ căn bậc hai của d_k?',   '{"options": {"A": "Để giảm bớt số lượng tham số cần huấn luyện.", "B": "Để tránh hiện tượng gradient bị triệt tiêu khi d_k lớn.", "C": "Để tăng tốc độ nhân hai ma trận Q và K.", "D": "Để chuyển đổi giá trị đầu ra trực tiếp thành xác suất."}, "correct": "B", "explanation": "Khi số chiều d_k của Key quá lớn, phép nhân vô hướng QK^T sẽ tạo ra các giá trị cực lớn, làm cho hàm softmax có gradient rất nhỏ (triệt tiêu gradient). Phép chia giúp làm ổn định giá trị này."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '62e0ea01-00fa-5b04-b444-1813b221c206',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Cơ chế Multi-Head Attention trong Transformer được thiết kế nhằm mục đích chính nào?',   '{"options": {"A": "Tăng gấp đôi dung lượng cửa sổ ngữ cảnh đầu vào.", "B": "Cho phép chạy mô hình trên nhiều GPU song song.", "C": "Giảm thiểu thời gian tính toán tại các lớp mạng.", "D": "Cho phép chú ý đồng thời vào nhiều vị trí."}, "correct": "D", "explanation": "Bằng cách chia nhỏ vector biểu diễn thành nhiều head riêng biệt, Multi-Head Attention giúp mô hình học được nhiều mối quan hệ ngữ cảnh và ngữ pháp khác nhau cùng lúc."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '33b7c566-d231-5827-9de3-3750f19aa874',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Trong khối Transformer, chức năng chính của lớp Layer Normalization là gì?',   '{"options": {"A": "Ổn định quá trình huấn luyện và tối ưu hóa gradient.", "B": "Thay thế hoàn toàn cho các hàm kích hoạt phi tuyến.", "C": "Chuyển đổi các từ đầu vào thành các vectơ embedding.", "D": "Tính toán trọng số liên kết giữa các token xa nhau."}, "correct": "A", "explanation": "Layer Normalization chuẩn hóa đầu ra của mỗi lớp con, giúp phân phối đặc trưng ổn định hơn, từ đó tăng tốc độ hội tụ và giảm thiểu biến động gradient trong quá trình huấn luyện."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '69061e48-c2bc-59a7-a140-9d3b540c5f65',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Phần Encoder của Transformer gốc xử lý chuỗi đầu vào theo cơ chế chú ý nào?',   '{"options": {"A": "Cơ chế Masked Attention ẩn đi các token phía sau.", "B": "Cơ chế Causal Attention dự đoán các từ tiếp theo.", "C": "Cơ chế Bidirectional Attention giúp nhìn được cả hai hướng.", "D": "Cơ chế Cross Attention kết hợp thông tin giải mã."}, "correct": "C", "explanation": "Encoder trong Transformer xử lý toàn bộ ngữ cảnh đầu vào cùng một lúc, cho phép mỗi token chú ý đến tất cả các token khác nằm trước và sau nó (bidirectional)."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '3ceed05c-b5c9-5184-9d74-b0292fb92d8c',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Một mô hình Transformer gặp hiện tượng mất ổn định gradient khi huấn luyện với vector embedding rất lớn (d_k > 1024). Lỗi này thường do việc thiếu bước nào trong attention?',   '{"options": {"A": "Thiếu lớp Residual Connection kết nối giữa các khối mạng.", "B": "Thiếu phép chia cho căn bậc hai số chiều d_k.", "C": "Thiếu hàm kích hoạt phi tuyến tại các lớp mạng.", "D": "Thiếu cơ chế Masked Attention tại phần Decoder mô hình."}, "correct": "B", "explanation": "Nếu thiếu phép chia scale theo căn bậc hai của d_k, giá trị dot product sẽ cực kỳ lớn khiến hàm softmax bị bão hòa, dẫn đến gradient cực nhỏ ở các lớp dưới và gây mất ổn định huấn luyện."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'b8372351-e268-5dd8-a3d2-220f8988769b',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Cơ chế Residual Connection (Kết nối tắt) trong khối Transformer có tác dụng gì?',   '{"options": {"A": "Giảm số lượng tham số huấn luyện của mô hình.", "B": "Tự động điều chỉnh kích thước của Context Window thô.", "C": "Loại bỏ hoàn toàn sự cần thiết của Position Embedding.", "D": "Giúp truyền gradient hiệu quả qua các lớp mạng sâu."}, "correct": "D", "explanation": "Residual Connection cộng trực tiếp đầu vào của một khối vào đầu ra của nó, tạo ra một đường truyền gradient không bị suy giảm trực tiếp về các lớp dưới, giúp huấn luyện mô hình rất sâu."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '8430bde2-b5cc-57c3-a7d4-e15acdb38f73',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Khi phân tích ma trận trọng số Attention của một câu, bạn thấy từ "nó" có trọng số liên kết rất cao với từ "con chó" đứng cách đó 10 từ. Cơ chế nào đã trực tiếp thực hiện việc này?',   '{"options": {"A": "Cơ chế Self-Attention tính toán độ tương đồng ngữ nghĩa.", "B": "Cơ chế Layer Normalization chuẩn hóa biên độ vectơ từ.", "C": "Lớp Feed-Forward Network biến đổi phi tuyến các đặc trưng.", "D": "Cơ chế Masked Attention lọc bỏ các từ đứng sau nó."}, "correct": "A", "explanation": "Cơ chế Self-Attention tính toán dot product giữa Query của từ ''nó'' và Key của từ ''con chó'', xác định độ tương đồng ngữ nghĩa cao và tập trung phân bổ trọng số vào đó."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '53369628-3e85-5698-bc94-d71bb2c7518c',   '00000000-0000-0000-0000-000000000001',   '00000000-0000-0000-0000-000000000101',   'mcq',   'Trong khối Decoder của kiến trúc Transformer gốc, tại sao cần sử dụng Masked Self-Attention thay vì Self-Attention thông thường?',   '{"options": {"A": "Để ngăn chặn việc mô hình chạy song song trên GPU.", "B": "Để ngăn Decoder nhìn thấy trước các token ở tương lai.", "C": "Để giảm thiểu số lượng phép nhân ma trận trọng số.", "D": "Để loại bỏ sự phụ thuộc vào lớp Cross-Attention kết nối."}, "correct": "B", "explanation": "Trong quá trình sinh văn bản tự hồi quy, mô hình chỉ được phép biết các token đã sinh ra ở phía trước. Lớp mặt nạ (mask) che các token tương lai để đảm bảo tính nhân quả."}'::jsonb,   900.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.concepts (id, course_id, code, name, status) VALUES ('692883f0-e31a-5475-8fca-a1f4c6b49601', '00000000-0000-0000-0000-000000000001', 'day1-tokenization', 'Phần 2: Tokenization & Kỹ thuật Embeddings', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'ea3ce8c3-38bd-5084-82df-93853e238213',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Tokenizer có nhiệm vụ chính nào trong quá trình xử lý ngôn ngữ đầu vào của LLM?',   '{"options": {"A": "Chuyển đổi các token đầu vào trực tiếp thành vector nhúng.", "B": "Chia nhỏ văn bản thô thành các đơn vị token con.", "C": "Tính toán điểm tương đồng ngữ nghĩa giữa các câu văn.", "D": "Chuẩn hóa biên độ giá trị của các vector đặc trưng."}, "correct": "B", "explanation": "Tokenizer chuyển đổi văn bản thô dạng chuỗi ký tự thành một chuỗi các token con (từ hoặc cụm từ con) và ánh xạ chúng thành các ID tương ứng trong từ điển."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '33c1d77e-4903-510a-83c6-477a1c6207cb',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Tại sao các LLM hiện đại thường dùng Subword Tokenization thay vì tách theo từng từ nguyên vẹn?',   '{"options": {"A": "Để giảm bớt số lượng GPU cần dùng khi suy luận.", "B": "Để tăng kích thước của Context Window lên tối đa.", "C": "Để loại bỏ hoàn toàn các ký tự đặc biệt đầu vào.", "D": "Để xử lý từ chưa biết và tối ưu hóa từ vựng."}, "correct": "D", "explanation": "Subword Tokenization giúp xử lý tốt các từ hiếm hoặc từ mới chưa từng xuất hiện (Out-of-Vocabulary) bằng cách ghép các mảnh từ con, đồng thời giữ kích thước từ điển nhỏ gọn."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '421574c8-5d08-5cd1-849d-562d730afa61',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Thuật toán Byte-Pair Encoding (BPE) bắt đầu quá trình huấn luyện bằng cách nào?',   '{"options": {"A": "Khởi tạo từ điển chứa các ký tự đơn lẻ.", "B": "Tách văn bản thô dựa trên các khoảng trắng.", "C": "Hợp nhất các từ có cùng ý nghĩa ngữ nghĩa.", "D": "Đếm tần suất xuất hiện của các từ nguyên vẹn."}, "correct": "A", "explanation": "BPE khởi đầu bằng cách coi mỗi ký tự đơn lẻ là một token, sau đó lặp đi lặp lại việc ghép cặp hai token kề nhau xuất hiện nhiều nhất trong văn bản thành một token mới."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'fd992563-178e-5157-9a82-42db3fff6893',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Điểm khác biệt lớn nhất giúp SentencePiece xử lý tốt đa ngôn ngữ hơn BPE truyền thống là gì?',   '{"options": {"A": "Khả năng tự động sửa lỗi chính tả trong văn bản.", "B": "Tốc độ mã hóa nhanh hơn nhờ cấu trúc mạng nơ-ron.", "C": "Coi khoảng trắng là một ký tự và không tiền xử lý.", "D": "Giới hạn kích thước từ điển nhỏ dưới 1000 từ."}, "correct": "C", "explanation": "SentencePiece coi toàn bộ văn bản là chuỗi ký tự thô và thay khoảng trắng bằng ký tự đặc biệt (như ''_''). Nó không cần bước tiền tách từ bằng khoảng cách, phù hợp cho tiếng Trung/Nhật."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '71988d52-8959-5008-a4c1-b5ad22b98407',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Trong từ điển của Tokenizer, các token như <BOS>, <EOS> được dùng để làm gì?',   '{"options": {"A": "Đại diện cho các từ bị thiếu trong quá trình nhúng.", "B": "Đánh dấu điểm bắt đầu và kết thúc của một chuỗi.", "C": "Tăng tốc độ tính toán ma trận Attention của Decoder.", "D": "Phân chia các đoạn văn bản có độ dài khác nhau."}, "correct": "B", "explanation": "Token đặc biệt <BOS> (Begin of Sequence) và <EOS> (End of Sequence) giúp mô hình biết được ranh giới bắt đầu và kết thúc của một đoạn văn bản trong quá trình sinh hoặc huấn luyện."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '13813f02-0681-547f-ba06-25f9a90ce852',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Một kỹ sư AI phát hiện mô hình sinh ra lỗi khi gặp ký tự lạ "¶". Kỹ thuật nào giúp tránh lỗi từ lạ (Out-Of-Vocabulary) này?',   '{"options": {"A": "Chuyển đổi toàn bộ ký tự lạ thành các dấu cách.", "B": "Thiết lập giá trị mặc định cho lớp Layer Normalization.", "C": "Tăng kích thước từ điển của mô hình lên gấp đôi.", "D": "Phân rã từ lạ thành các byte ký tự cơ bản."}, "correct": "D", "explanation": "Các tokenizer hiện đại (như Byte-level BPE của GPT) phân rã các ký tự Unicode lạ thành dạng byte cơ bản, giúp mô hình luôn biểu diễn được mọi ký tự lạ mà không bị lỗi OOV."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '49201be3-eebb-5d06-a8cd-98bb73333e9f',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Khi một đoạn văn bản được đưa vào lớp Embedding, mỗi token sẽ được chuyển đổi thành gì?',   '{"options": {"A": "Một vectơ số thực có kích thước cố định trước.", "B": "Một ma trận chứa các chỉ số token trong từ điển.", "C": "Một giá trị xác suất duy nhất nằm từ 0 đến 1.", "D": "Một chuỗi các byte nhị phân để máy tính đọc."}, "correct": "A", "explanation": "Lớp Embedding ánh xạ ID của token thành một vectơ số thực nhiều chiều (ví dụ 4096 chiều trong Llama), biểu diễn ngữ nghĩa của từ trong không gian vector toán học."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'b1caba4a-ca22-5d11-8313-fe5f1e85016d',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Tại sao trong tiếng Việt, cụm từ "học sinh" đôi khi bị Tokenizer tách thành các token rời rạc như "học" và " sinh"?',   '{"options": {"A": "Do lớp Embedding không nhận dạng được ngôn ngữ tiếng Việt.", "B": "Do thuật toán BPE bắt buộc phải loại bỏ các dấu tiếng Việt.", "C": "Do từ điển huấn luyện của Tokenizer chưa học từ ghép này.", "D": "Do khoảng trắng giữa hai từ làm đứt gãy ma trận Attention."}, "correct": "C", "explanation": "If dữ liệu huấn luyện Tokenizer không chứa đủ số lần xuất hiện ghép của hai từ này, thuật toán sẽ không gộp chúng lại làm một token và giữ chúng ở dạng các subwords đơn lẻ."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '1d808306-539c-5e3f-886f-d0d2efceb6ff',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Bạn ước lượng token cho một tài liệu tiếng Việt dài 1000 từ. Tỉ lệ số lượng token so với số từ thực tế thường là bao nhiêu?',   '{"options": {"A": "Số lượng token bằng khoảng 50% số từ thực tế.", "B": "Số lượng token bằng khoảng 120% đến 150% số từ.", "C": "Số lượng token luôn bằng chính xác số từ thực tế.", "D": "Số lượng token bằng khoảng 300% trở lên số từ."}, "correct": "B", "explanation": "Với tiếng Việt, do đặc thù nhiều từ ghép và dấu thanh, tokenizer của các mô hình đa ngôn ngữ thường phân rã các từ thành nhiều subwords, dẫn đến tỉ lệ token thường bằng 1.2 đến 1.5 lần số từ."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'fe98c1be-f4ad-50ad-86a2-8f36b113e888',   '00000000-0000-0000-0000-000000000001',   '692883f0-e31a-5475-8fca-a1f4c6b49601',   'mcq',   'Trong thuật toán WordPiece, tiêu chí để quyết định hợp nhất (merge) hai subword A và B thành AB là gì?',   '{"options": {"A": "Tối đa hóa khả năng xuất hiện của tập dữ liệu.", "B": "Tổng tần suất xuất hiện của cả hai subword đó.", "C": "Khoảng cách ngữ nghĩa giữa hai vectơ embedding của chúng.", "D": "Độ dài ký tự vật lý của từ sau ghép."}, "correct": "A", "explanation": "WordPiece lựa chọn cặp ghép giúp tối đa hóa khả năng (likelihood) của tập dữ liệu huấn luyện dựa trên mô hình ngôn ngữ (xác suất xuất hiện của AB lớn nhất so với xác suất đơn lẻ của A và B)."}'::jsonb,   1100.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.concepts (id, course_id, code, name, status) VALUES ('c09048e6-20a3-5b5f-b9ea-ef46078d0790', '00000000-0000-0000-0000-000000000001', 'day1-llm-architecture', 'Phần 3: Kiến trúc LLM & Quản lý Ngữ cảnh', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'ec9184ee-5c06-57f6-b78b-44c73928c8e9',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Các mô hình ngôn ngữ lớn phổ biến hiện nay như GPT và Llama sử dụng kiến trúc nào?',   '{"options": {"A": "Kiến trúc mạng nơ-ron hồi quy có hướng.", "B": "Kiến trúc Encoder-only dựa trên mô hình BERT.", "C": "Kiến trúc Encoder-Decoder dựa trên mô hình T5.", "D": "Kiến trúc Decoder-only hoạt động theo kiểu tự hồi quy."}, "correct": "D", "explanation": "Các LLM hiện đại chủ yếu sử dụng kiến trúc Decoder-only tự hồi quy (autoregressive), dự đoán token tiếp theo chỉ dựa trên các token đã xuất hiện trước đó."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '893471be-ca1c-541a-a687-84ab1e260fae',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Kiến trúc Encoder-Decoder (như T5) thường phù hợp nhất với loại tác vụ nào dưới đây?',   '{"options": {"A": "Trò chuyện tự do và sinh mã nguồn liên tục.", "B": "Phân tích cảm xúc văn bản dựa trên từ khóa.", "C": "Dịch thuật song ngữ và tóm tắt văn bản thô.", "D": "Tìm kiếm thông tin ngữ nghĩa trong cơ sở dữ liệu."}, "correct": "C", "explanation": "Kiến trúc Encoder-Decoder rất mạnh trong các tác vụ biến đổi chuỗi nguồn sang chuỗi đích (sequence-to-sequence) như dịch thuật hoặc tóm tắt nội dung văn bản."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '43739e17-0ea2-5401-85c5-1c7b08b64469',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Mục đích chính của kỹ thuật KV Cache (Key-Value Cache) trong suy luận LLM là gì?',   '{"options": {"A": "Tránh việc tính toán lại vectơ K và V cũ.", "B": "Giảm kích thước bộ nhớ GPU cần dùng khi chạy.", "C": "Tự động mở rộng Context Window của mô hình lên.", "D": "Nâng cao độ chính xác toán học của kết quả."}, "correct": "A", "explanation": "Trong quá trình suy luận tự hồi quy, các token trước đó không thay đổi ngữ nghĩa. KV Cache lưu trữ các vectơ K và V của chúng để tránh việc tính toán lại từ đầu tại mỗi bước sinh từ mới."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '428c1ba1-2bf0-5804-b81e-9b233dcf2e3f',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Rotary Positional Embedding (RoPE) mã hóa thông tin vị trí vào mô hình bằng cách nào?',   '{"options": {"A": "Cộng trực tiếp vector vị trí vào embedding từ đầu.", "B": "Thực hiện phép quay các vectơ Query và Key.", "C": "Nhân ma trận trọng số Attention với một hằng số.", "D": "Cấu hình ma trận mask để che đi vị trí sau."}, "correct": "B", "explanation": "RoPE sử dụng phép nhân ma trận quay để mã hóa thông tin vị trí tương đối trực tiếp vào vectơ Query và Key, giúp mô hình nắm bắt khoảng cách tương đối giữa các token hiệu quả hơn."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'ef27d833-11da-5929-ae72-f0c344868866',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Điều gì xảy ra khi độ dài đầu vào vượt quá giới hạn Context Window của một LLM?',   '{"options": {"A": "Mô hình sẽ tự động tăng kích thước vector nhúng.", "B": "Mô hình sẽ chạy nhanh hơn nhờ bỏ qua từ cũ.", "C": "Mô hình sẽ báo lỗi biên dịch hệ thống ngay lập tức.", "D": "Mô hình sẽ bị quên hoặc mất thông tin ban đầu."}, "correct": "D", "explanation": "Khi vượt quá kích thước cửa sổ ngữ cảnh vật lý của mô hình, phần thông tin vượt quá sẽ bị cắt bỏ hoặc trôi ra khỏi bộ nhớ đệm chú ý, làm mô hình không thể nhớ các chỉ dẫn ban đầu."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '9b2298c0-c707-55d6-af50-0f8f575baf6e',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Một máy chủ chạy LLM bị tràn bộ nhớ VRAM của GPU khi độ dài hội thoại tăng lên, mặc dù kích thước mô hình tĩnh không đổi. Nguyên nhân chính do đâu?',   '{"options": {"A": "Kích thước từ điển của Tokenizer tự động phình to.", "B": "Lớp Layer Normalization sinh ra các giá trị rất lớn.", "C": "Bộ nhớ KV Cache tích lũy liên tục theo chiều dài.", "D": "Hệ số scale của cơ chế Self-Attention tăng quá mức."}, "correct": "C", "explanation": "Bộ nhớ dành cho KV Cache phình to tuyến tính theo chiều dài chuỗi hội thoại đầu vào và số lượng câu sinh ra, dẫn đến hiện tượng tràn VRAM trên GPU khi hội thoại quá dài."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '822e7086-5323-54b1-9443-5ff2ca2a54a6',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Bạn muốn xây dựng một hệ thống chatbot chăm sóc khách hàng có khả năng nhớ lịch sử hội thoại dài. Phương pháp mở rộng ngữ cảnh nào ít tốn chi phí huấn luyện lại nhất?',   '{"options": {"A": "Áp dụng phương pháp ngoại suy vị trí dựa trên RoPE.", "B": "Tăng kích thước chiều của vector nhúng lên gấp đôi.", "C": "Huấn luyện lại mô hình từ đầu với câu cực dài.", "D": "Thay thế hoàn toàn cơ chế Self-Attention bằng mạng RNN."}, "correct": "A", "explanation": "Mã hóa vị trí RoPE hỗ trợ tốt khả năng ngoại suy độ dài (extrapolation). Các kỹ thuật như RoPE Scaling cho phép mở rộng ngữ cảnh của mô hình mà không cần huấn luyện lại từ đầu."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '687beb75-cec5-5d42-be82-241d36206bcb',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Khi so sánh chi phí bộ nhớ KV Cache, phương pháp Multi-Query Attention (MQA) giúp giảm tải bộ nhớ so với Multi-Head Attention (MHA) gốc bằng cách nào?',   '{"options": {"A": "Sử dụng một vector Value duy nhất cho tất cả token.", "B": "Dùng chung một đầu Key và Value cho các head.", "C": "Loại bỏ hoàn toàn ma trận Query khỏi quá trình sinh.", "D": "Giảm số lượng tham số huấn luyện của lớp feed-forward."}, "correct": "B", "explanation": "MQA tối ưu KV Cache bằng cách giữ nguyên số đầu Query (M head) nhưng chỉ sử dụng duy nhất 1 đầu Key và 1 đầu Value dùng chung cho tất cả các head, giúp tiết kiệm dung lượng cache VRAM."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '32276e48-35b9-56c0-a9dc-535c6d53cc94',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Tại sao việc mã hóa vị trí tương đối (như RoPE) lại ưu việt hơn mã hóa vị trí tuyệt đối (như trong Transformer gốc)?',   '{"options": {"A": "Nó giúp giảm số lượng ma trận trọng số cần học.", "B": "Nó cho phép mô hình chạy song song hóa tốt hơn.", "C": "Nó loại bỏ hoàn toàn sự cần thiết của hàm Softmax.", "D": "Nó giúp mô hình suy luận tốt với chuỗi cực dài."}, "correct": "D", "explanation": "Mã hóa vị trí tương đối giữ nguyên cấu trúc ngữ nghĩa khoảng cách giữa các token độc lập với vị trí tuyệt đối của chúng trong câu, hỗ trợ mô hình xử lý tốt và ngoại suy các chuỗi dài hơn."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'b3aa4dd6-d3f3-575b-a3c3-a86d3dfe3662',   '00000000-0000-0000-0000-000000000001',   'c09048e6-20a3-5b5f-b9ea-ef46078d0790',   'mcq',   'Bạn đang thiết kế một ứng dụng RAG và nhận thấy mô hình Decoder-only hoạt động kém hiệu quả khi thông tin tìm kiếm nằm ở giữa context window dài. Hiện tượng này được gọi là gì?',   '{"options": {"A": "Hiện tượng gradient biến mất trong chuỗi dài liên tục.", "B": "Hiện tượng Lost in the Middle của phân phối attention.", "C": "Hiện tượng suy giảm tính đa dạng của tokenizer subword.", "D": "Hiện tượng lệch phân phối dữ liệu huấn luyện ban đầu."}, "correct": "B", "explanation": "Nghiên cứu chỉ ra các mô hình ngôn ngữ Decoder-only thường chú ý tốt nhất ở phần đầu (chỉ dẫn) và phần cuối (câu hỏi) của ngữ cảnh, trong khi bỏ sót hoặc chú ý kém ở phần giữa (Lost in the Middle)."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.concepts (id, course_id, code, name, status) VALUES ('0a1dcbb4-5036-5790-95d1-16e53e3f8309', '00000000-0000-0000-0000-000000000001', 'day1-inference-decoding', 'Phần 4: Tham số giải mã & Inference Dynamics', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '652a99f2-5f07-5c42-8ded-605e38913d3f',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Trong quá trình suy luận, giá trị raw đầu ra từ lớp cuối cùng của LLM trước khi qua Softmax được gọi là gì?',   '{"options": {"A": "Các giá trị Logits đại diện cho điểm số.", "B": "Các giá trị Embeddings đại diện cho từ ghép.", "C": "Các giá trị Attentions đại diện cho ngữ cảnh câu.", "D": "Các giá trị Normalizations đại diện cho phân phối số."}, "correct": "A", "explanation": "Logits là các giá trị điểm số thô chưa được chuẩn hóa được mô hình tính toán cho từng token trong từ điển trước khi đưa qua hàm softmax để chuyển đổi thành phân phối xác suất."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '355bdcef-a914-5a27-bd81-a2faf388929d',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Khi đặt tham số Temperature bằng 0, mô hình sẽ sinh văn bản theo cách nào?',   '{"options": {"A": "Lấy mẫu hoàn toàn ngẫu nhiên từ phân phối xác suất.", "B": "Luôn chọn từ có xác suất cao nhất tại mỗi bước.", "C": "Tự động loại bỏ tất cả các token đặc biệt đầu ra.", "D": "Tạo ra văn bản có độ sáng tạo và bất ngờ lớn."}, "correct": "B", "explanation": "Đặt Temperature bằng 0 chuyển mô hình sang trạng thái Greedy Decoding (giải mã tham lam), tức là luôn chọn token có xác suất cao nhất tại mỗi bước, kết quả sinh ra sẽ hoàn toàn ổn định và lặp lại được."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'bdcaf7e7-4d32-5a69-8238-a6023d732003',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Tham số Top-k hoạt động như thế nào trong bước lấy mẫu (sampling) của LLM?',   '{"options": {"A": "Chỉ giữ lại các từ xuất hiện trong k đoạn văn.", "B": "Lọc các từ có số ký tự vật lý nhỏ hơn k.", "C": "Tính toán lại ma trận attention cho k token cũ.", "D": "Giới hạn lựa chọn trong k token có xác suất cao nhất."}, "correct": "D", "explanation": "Top-k lọc phân phối xác suất để chỉ giữ lại k token có điểm số cao nhất, sau đó phân phối lại xác suất của k từ này để tiến hành lấy mẫu tiếp theo, loại bỏ các từ vô nghĩa hoặc ngoại lai."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'f41fd3b8-f7da-56f9-8e97-a13e6a64c3f0',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Tham số Top-p (hay Nucleus Sampling) lọc danh sách token dựa trên tiêu chí nào?',   '{"options": {"A": "Chọn cố định p phần trăm số từ trong từ điển.", "B": "Chọn các từ có độ dài vector nhúng lớn hơn p.", "C": "Chọn nhóm từ có tổng xác suất tích lũy đạt mức p.", "D": "Loại bỏ các từ xuất hiện ít hơn p lần trong câu."}, "correct": "C", "explanation": "Top-p chọn tập hợp các token có xác suất lớn nhất sao cho tổng xác suất của chúng vừa đủ vượt qua ngưỡng p (ví dụ 0.90), giúp linh hoạt điều chỉnh số lượng token được chọn tùy vào độ tự tin của mô hình."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '11c9e84a-e783-5b18-99b1-a466bdc34d0b',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Tác động chính của việc tăng tham số Temperature (> 1.0) lên đầu ra của LLM là gì?',   '{"options": {"A": "Làm phẳng phân phối xác suất và tăng độ đa dạng.", "B": "Tăng độ dài tối đa của câu được sinh ra.", "C": "Giúp mô hình chạy nhanh hơn bằng cách giảm tính toán.", "D": "Loại bỏ hoàn toàn lỗi ngữ pháp trong câu trả lời."}, "correct": "A", "explanation": "Tăng Temperature làm phẳng phân phối xác suất của logits, khiến sự chênh lệch xác suất giữa các từ giảm đi. Điều này tăng khả năng các từ ít phổ biến được chọn, làm câu trả lời sáng tạo và đa dạng hơn."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'eff421ab-c786-546d-bc13-50f5bba82be0',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Bạn đang viết code gọi API của GPT để trích xuất thông tin JSON từ văn bản. Thiết lập tham số giải mã nào là phù hợp nhất?',   '{"options": {"A": "Đặt giá trị Temperature cao và đặt Top p bằng một.", "B": "Đặt giá trị Temperature gần không và dùng Greedy Decoding.", "C": "Đặt giá trị Top k lớn và tắt bộ lọc này.", "D": "Không truyền bất kỳ tham số cấu hình hệ thống nào."}, "correct": "B", "explanation": "Khi trích xuất dữ liệu có định dạng cố định (như JSON) đòi hỏi độ chính xác và tính nhất quán cao nhất, ta nên đặt Temperature về sát 0 để mô hình chọn các từ chắc chắn và logic nhất."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '3b16c589-c7d3-5aef-8c23-6f2ea5ee3231',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Tại sao nhiều hướng dẫn khuyến nghị không nên đồng thời thay đổi cả Temperature và Top-p khi gọi API của LLM?',   '{"options": {"A": "Vì sẽ gây lỗi biên dịch mã nguồn của ứng dụng.", "B": "Vì sẽ làm tăng gấp đôi thời gian phản hồi của API.", "C": "Vì chúng sẽ tự động triệt tiêu lẫn nhau hoàn toàn.", "D": "Vì khó kiểm soát được chất lượng và tính ổn định."}, "correct": "D", "explanation": "Cả hai tham số đều thay đổi phân phối xác suất lấy mẫu. Điều chỉnh đồng thời cả hai làm thay đổi không kiểm soát được quá trình sinh văn bản và gây khó khăn khi tinh chỉnh hành vi của mô hình."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '265ca01a-b6ff-57c2-9089-acef3affc642',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Một chatbot viết truyện ngắn sáng tạo đôi khi sinh ra các câu bị lặp từ liên tục. Bạn nên làm thế nào để khắc phục lỗi này?',   '{"options": {"A": "Giảm giới hạn context window của mô hình xuống thấp.", "B": "Tắt hoàn toàn tham số Top-k và Top-p của hệ thống.", "C": "Tăng giá trị tham số Frequency Penalty hoặc Presence Penalty.", "D": "Chuyển sang sử dụng hàm kích hoạt khác trong mạng."}, "correct": "C", "explanation": "Frequency Penalty phạt trực tiếp vào các từ xuất hiện nhiều lần, còn Presence Penalty phạt các từ đã xuất hiện trong câu, giúp khuyến khích mô hình sinh ra các từ mới lạ hơn và hạn chế lặp từ."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'c4e62249-4174-5c9d-a629-56c59d8e4972',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Bạn cấu hình System Prompt để đóng vai một chuyên gia tư vấn tài chính. Tại sao System Prompt lại có ảnh hưởng mạnh mẽ xuyên suốt cuộc hội thoại?',   '{"options": {"A": "Nó được tiêm vào vị trí đầu tiên trong context window.", "B": "Nó tự động tăng độ ưu tiên xác suất của mọi từ.", "C": "Nó chạy trực tiếp qua bộ nhớ đệm KV Cache riêng.", "D": "Nó thay thế hoàn toàn các chỉ dẫn từ phía người dùng."}, "correct": "A", "explanation": "Do cơ chế Attention trong Decoder-only, các từ sau chú ý vào các từ trước. System Prompt nằm ở vị trí đầu tiên của Context Window, đóng vai trò định hướng ngữ cảnh cho mọi token sinh ra sau đó."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '15f79bf4-3136-50bb-90c1-96e6a1314d7f',   '00000000-0000-0000-0000-000000000001',   '0a1dcbb4-5036-5790-95d1-16e53e3f8309',   'mcq',   'Trong quá trình Auto-regressive decoding, tại sao việc sinh token mới bắt buộc phải thực hiện tuần tự từng bước một?',   '{"options": {"A": "Vì kích thước mô hình quá lớn để chạy song song.", "B": "Vì token tiếp theo cần dựa vào token vừa sinh ra.", "C": "Vì lớp Layer Normalization giới hạn tốc độ truyền tin.", "D": "Vì các giá trị logits của từ điển cần được xếp hạng."}, "correct": "B", "explanation": "Auto-regressive decoding (giải mã tự hồi quy) hoạt động bằng cách dự đoán token thứ N dựa trên chuỗi có sẵn N-1 token. Do đó, mô hình bắt buộc phải sinh tuần tự từng từ một chứ không thể chạy song song."}'::jsonb,   1300.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.question_hints (id, question_id, level, hint_text) VALUES ('3bde5f76-0784-5ccd-b3ef-bf2ed40c2121', '15f79bf4-3136-50bb-90c1-96e6a1314d7f', 1, 'Hãy cân nhắc về lý do tại sao quá trình này cần phải tuần tự.') ON CONFLICT (question_id, level) DO UPDATE SET hint_text = EXCLUDED.hint_text;
INSERT INTO app.question_hints (id, question_id, level, hint_text) VALUES ('f306540e-c497-549f-8ad2-bb730d4cba0e', '15f79bf4-3136-50bb-90c1-96e6a1314d7f', 2, 'Nếu mỗi token phụ thuộc vào token trước đó, bạn có thể giải thích điều này không?') ON CONFLICT (question_id, level) DO UPDATE SET hint_text = EXCLUDED.hint_text;
INSERT INTO app.question_hints (id, question_id, level, hint_text) VALUES ('2452d2a4-74a1-51bf-8519-f4abbe6919bc', '15f79bf4-3136-50bb-90c1-96e6a1314d7f', 3, 'Hãy nghĩ về cách mà mô hình xử lý các đầu ra từng bước một có thể ảnh hưởng đến khả năng sinh ra.') ON CONFLICT (question_id, level) DO UPDATE SET hint_text = EXCLUDED.hint_text;
INSERT INTO app.concepts (id, course_id, code, name, status) VALUES ('90b94754-d194-5118-af64-b5a6866ecaa1', '00000000-0000-0000-0000-000000000001', 'day1-short-answer', 'Tự luận: Nền tảng AI & Kiến trúc LLM Thực chiến', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '263c85ac-da5f-58cb-af7b-be10af15725c',   '00000000-0000-0000-0000-000000000001',   '90b94754-d194-5118-af64-b5a6866ecaa1',   'short_answer',   'Một lập trình viên cần gọi OpenAI API để trích xuất thông tin có cấu trúc từ log tiếng Việt và yêu cầu kết quả trả về hoàn toàn nhất quán (deterministic). Hãy đề xuất cấu hình tham số suy luận và ước lượng sự khác biệt về chi phí token so với văn bản tiếng Anh.',   '{"expected_answer": "Đặt temperature = 0 (hoặc dùng top_p gần 0) để có tính nhất quán cao. Tiếng Việt sử dụng Unicode và các ký tự có dấu thanh, thuật toán tokenization (như BPE) sẽ chia nhỏ từ thành nhiều subwords hơn, dẫn đến chi phí token cao hơn từ 1.2x đến 1.5x so với tiếng Anh cho cùng nội dung.", "evaluation_points": ["Đề xuất đặt temperature = 0 hoặc top_p = 0 để đạt tính nhất quán tối đa.", "Giải thích cơ chế tokenization (BPE) phân rã tiếng Việt thành nhiều subwords do ký tự Unicode có dấu thanh.", "Ước lượng tỷ lệ chênh lệch token thực tế khoảng 1.2x đến 1.5x so với tiếng Anh."], "sfia_level": "SFIA L3", "competency": "Cấu hình tham số API và ước lượng chi phí Token Economy"}'::jsonb,   1000.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '6b379128-6041-5fa8-b529-8f6650c2744e',   '00000000-0000-0000-0000-000000000001',   '90b94754-d194-5118-af64-b5a6866ecaa1',   'short_answer',   'Trong quá trình vận hành một chatbot hỗ trợ khách hàng, hệ thống liên tục ghi nhận lỗi Out-Of-Vocabulary (OOV) khi người dùng nhập các ký tự đặc biệt, emoji lạ hoặc từ viết tắt. Hãy giải thích cách các tokenizer hiện đại (như Byte-level BPE) xử lý triệt để vấn đề này.',   '{"expected_answer": "Byte-level BPE không bắt đầu từ ký tự Unicode đơn lẻ mà phân rã các ký tự lạ thành chuỗi byte cơ bản (ASCII/UTF-8). Vì tập hợp byte chỉ gồm 256 giá trị cơ bản, tokenizer luôn có thể biểu diễn bất kỳ từ mới hoặc ký tự lạ nào bằng cách ghép các byte, từ đó triệt tiêu hoàn toàn lỗi Out-Of-Vocabulary (OOV).", "evaluation_points": ["Nêu được cơ chế phân rã ký tự Unicode thành các byte UTF-8 cơ bản.", "Giải thích tập hợp byte cơ bản (256 giá trị) được chứa sẵn trong từ điển tokenizer.", "Khẳng định việc biểu diễn ký tự lạ bằng chuỗi byte giúp loại bỏ hoàn toàn lỗi OOV."], "sfia_level": "SFIA L3", "competency": "Chẩn đoán và xử lý vấn đề mã hóa/tokenizer trong ứng dụng NLP"}'::jsonb,   1000.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  'd4ed57af-27b5-5d55-b047-2e4df37e6712',   '00000000-0000-0000-0000-000000000001',   '90b94754-d194-5118-af64-b5a6866ecaa1',   'short_answer',   'Hệ thống chatbot của công ty bị tràn bộ nhớ VRAM của GPU khi độ dài cuộc hội thoại của người dùng tăng lên, mặc dù mô hình tĩnh không đổi kích thước. Hãy giải thích nguyên nhân gốc rễ và đề xuất cách tối ưu hóa bộ nhớ chú ý bằng cách so sánh Multi-Head Attention (MHA) với Multi-Query Attention (MQA).',   '{"expected_answer": "Nguyên nhân do KV Cache lưu trữ các vector Key và Value của các token trước đó tăng tuyến tính theo chiều dài chuỗi, gây phình to VRAM. Để tối ưu, Multi-Query Attention (MQA) giữ nguyên số đầu Query (M heads) nhưng chỉ dùng duy nhất 1 đầu Key và 1 đầu Value dùng chung cho tất cả các heads, giảm dung lượng KV Cache lưu trữ trên VRAM đáng kể.", "evaluation_points": ["Xác định nguyên nhân do sự phình to tuyến tính của KV Cache theo chiều dài hội thoại.", "Giải thích cơ chế hoạt động của Multi-Query Attention (MQA): chia sẻ chung 1 Key và 1 Value head cho nhiều Query heads.", "Kết luận MQA giúp giảm dung lượng VRAM lưu trữ so với MHA truyền thống."], "sfia_level": "SFIA L4", "competency": "Chẩn đoán lỗi bộ nhớ GPU và đề xuất giải pháp tối ưu hóa attention"}'::jsonb,   1200.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '2949b29c-7738-5396-a088-9bb6052cb2b9',   '00000000-0000-0000-0000-000000000001',   '90b94754-d194-5118-af64-b5a6866ecaa1',   'short_answer',   'Một kỹ sư muốn xây dựng một hệ thống phân tích báo cáo tài chính dài khoảng 40.000 tokens bằng cách tinh chỉnh mô hình có sẵn chỉ hỗ trợ Context Window là 8.000 tokens. Hãy so sánh sự khác biệt của Absolute Positional Encoding và Relative Positional Encoding (như RoPE) khi giải quyết bài toán ngoại suy ngữ cảnh này.',   '{"expected_answer": "Absolute Positional Encoding gán cứng vector vị trí tuyệt đối (từ 0 đến N-1), khiến mô hình không thể suy luận vượt quá chiều dài đã huấn luyện nếu không train lại. Relative Positional Encoding (như RoPE) mã hóa vị trí tương đối thông qua phép nhân ma trận xoay giữa Query và Key, cho phép áp dụng các kỹ thuật RoPE Scaling (như nội suy/ngoại suy tuyến tính) để kéo dài context window mà không cần huấn luyện lại từ đầu.", "evaluation_points": ["Chỉ ra hạn chế của Absolute Positional Encoding khi bị giới hạn cứng ở độ dài huấn luyện ban đầu.", "Giải thích cơ chế của RoPE sử dụng phép quay ma trận để giữ khoảng cách tương đối giữa các token.", "Mô tả cách thức RoPE Scaling giúp mở rộng ngữ cảnh mà không cần huấn luyện lại toàn bộ mô hình."], "sfia_level": "SFIA L4", "competency": "Thiết kế và mở rộng cửa sổ ngữ cảnh (Context Window Extension)"}'::jsonb,   1200.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
INSERT INTO app.questions (id, course_id, concept_id, type, prompt, answer_key, difficulty_elo, calibration_status) VALUES (  '6b462d92-4c63-5ac2-8e1f-0a6b70c8d822',   '00000000-0000-0000-0000-000000000001',   '90b94754-d194-5118-af64-b5a6866ecaa1',   'short_answer',   'Công ty bạn đang cân nhắc xây dựng một hệ thống AI Agent hỗ trợ viết code và vận hành CI/CD. Hãy so sánh và tư vấn giải pháp lựa chọn giữa: (1) Sử dụng API mô hình đóng cao cấp (như Claude Sonnet 4, GPT-4o) và (2) Tự host mô hình mã nguồn mở (như Llama 4) về các khía cạnh: Chi phí lâu dài, Độ trễ (Latency), Bảo mật dữ liệu mã nguồn doanh nghiệp, và năng lực lập kế hoạch (Reasoning/Planning).',   '{"expected_answer": "Mô hình đóng (API): Có năng lực suy luận/planning cực tốt (thích hợp cho tác vụ khó), không mất chi phí vận hành máy chủ ban đầu, nhưng chi phí tăng tuyến tính theo lượng token và rò rỉ mã nguồn bảo mật. Tự host (Llama 4): Bảo mật tuyệt đối vì chạy offline/private cloud, tối ưu chi phí khi có lượng request cực lớn, độ trễ có thể kiểm soát được bằng phần cứng tự có, nhưng đòi hỏi đầu tư GPU lớn ban đầu và năng lực suy luận có thể kém hơn một chút ở các task quá phức tạp.", "evaluation_points": ["Phân tích khía cạnh bảo mật dữ liệu doanh nghiệp (mô hình đóng có nguy cơ rò rỉ vs tự host an toàn tuyệt đối).", "So sánh cấu trúc chi phí (API trả theo lượng dùng thực tế vs tự host mất chi phí hạ tầng GPU lớn ban đầu nhưng rẻ khi scale).", "Đánh giá năng lực suy luận và lập kế hoạch (Reasoning/Planning) của mô hình đóng hiện tại vẫn vượt trội ở các task agent khó phức tạp.", "Đưa ra đề xuất cụ thể hoặc tiêu chí quyết định (ví dụ: dùng Hybrid hoặc chọn tự host khi bảo mật là ưu tiên số 1)."], "sfia_level": "SFIA L5", "competency": "Đánh giá kiến trúc hệ thống AI và quản trị rủi ro/chi phí doanh nghiệp"}'::jsonb,   1400.0,   'published') ON CONFLICT (id) DO UPDATE SET   prompt = EXCLUDED.prompt,   answer_key = EXCLUDED.answer_key,   difficulty_elo = EXCLUDED.difficulty_elo;
